/// <summary>
/// This is an UIBuilder class for VolumeFromCustomers report
/// </summary>
internal final class ETGVolumeFromCustomersUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGVolumeFromCustomersContract contract;
    DialogField dialogFromDate;
    DialogField dialogToDate;
    DialogField custAccount;
    DialogField deposit;
    DialogField invoiceId;
    DialogField size;

}

Method.Source:
public void build()
{
    contract            = this.dataContractObject() as ETGVolumeFromCustomersContract;
    dialogFromDate      = this.addDialogField(methodStr(ETGVolumeFromCustomersContract, parmFromDate), contract);
    dialogToDate        = this.addDialogField(methodStr(ETGVolumeFromCustomersContract, parmToDate), contract);
    custAccount         = this.addDialogField(methodStr(ETGVolumeFromCustomersContract, parmCustAccount), contract);
    deposit             = this.addDialogField(methodStr(ETGVolumeFromCustomersContract, parmDeposit), contract);
    invoiceId           = this.addDialogField(methodStr(ETGVolumeFromCustomersContract, parmInvoiceId), contract);
    size                = this.addDialogField(methodStr(ETGVolumeFromCustomersContract, parmSize), contract);

}

   public void postBuild()
   {
       Dialog dialogobj    = this.dialog();

       super();
       dialogFromDate      = this.bindInfo().getDialogField(contract, methodStr(ETGVolumeFromCustomersContract, parmFromDate));
       dialogToDate        = this.bindInfo().getDialogField(contract, methodStr(ETGVolumeFromCustomersContract, parmToDate));
       custAccount         = this.bindInfo().getDialogField(contract, methodStr(ETGVolumeFromCustomersContract, parmCustAccount));
       custAccount.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGVolumeFromCustomersUIBuilder, custAccountMultiSelectLookup), this);
       deposit             = this.bindInfo().getDialogField(contract, methodStr(ETGVolumeFromCustomersContract, parmDeposit));
       invoiceId           = this.bindInfo().getDialogField(contract, methodStr(ETGVolumeFromCustomersContract, parmInvoiceId));
       invoiceId.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGVolumeFromCustomersUIBuilder, InvoiceIdMultiSelectLookup), this);
       size                = this.bindInfo().getDialogField(contract, methodStr(ETGVolumeFromCustomersContract, parmSize));
//       size.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGVolumeFromCustomersUIBuilder,lookupSize),this);


       if(custAccount)
       {
           custAccount.lookupButton(2);
       }
       if(invoiceId)
       {
           invoiceId.lookupButton(2);
       }

   }

public void postRun()
{
    ETGVolumeFromCustomersContract etgVolumeFromCustomersContract = this.dataContractObject();
}

/// <summary>
/// This is lookup method for Cust account parameter
/// </summary>
/// <param name = "_formStringControl">FormStringControl</param>
public void custAccountMultiSelectLookup(FormStringControl _control)
{
    Query                 query = new Query();
    QueryBuildDataSource  qbds;
    container             conCustTable;

    qbds = query.addDataSource(tableNum(CustTable));

    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(CustTable,AccountNum));

    qbds = qbds.addDataSource(tableNum(DirPartyTable));
    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(DirPartyTable,Name));
    qbds.relations(true);
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conCustTable);
}

   /// <summary>
   /// Multi select lookup for InvoiceId parameter
   /// </summary>
   /// <param name = "_control">FormStringControl</param>
   public void InvoiceIdMultiSelectLookup(FormStringControl _control)
   {
       Query  query = new Query();
       QueryBuildDataSource qbds;
       container conInvoiceId;
       qbds = query.addDataSource(tableNum(CustInvoiceJour));
       qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceId));
       qbds.addSelectionField(fieldNum(CustInvoiceJour, SalesId));
       qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceAccount));
       SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conInvoiceId);
   }

